#include <stdio.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int upper[N], lower[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &upper[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &lower[i]);
    }
    int first[N];
    for (int i = 0; i < N; i++) {
        first[i] = 1;
    }
    for (int i = 0; i < M; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int L, R;
            scanf("%d %d", &L, &R);
            L--;
            R--;
            for (int j = L; j <= (L + R) / 2; j++) {
                int temp = upper[j];
                upper[j] = lower[R - j + L];
                lower[R - j + L] = temp;
                temp = lower[j];
                lower[j] = upper[R - j + L];
                upper[R - j + L] = temp;
            }
        } else if (type == 2) {
            int K;
            scanf("%d", &K);
            for (int j = 0; j < K; j++) {
                first[j] *= -1;
            }
        } else {
            int A, B, C, D;
            scanf("%d %d %d %d", &A, &B, &C, &D);
            A--;
            B--;
            C--;
            D--;
            long long sum = 0;
            for (int j = C; j <= D; j++) {
                if (j < B && j >= A) {
                    sum += first[j] * upper[j];
                } else {
                    sum += first[j] * lower[j];
                }
            }
            printf("%lld\n", sum);
        }
    }
    return 0;
}

